def relu(x): return max(0, x)

def neuron(inputs, weights, bias):
    raw = sum(w * x for w, x in zip(weights, inputs)) + bias
    return relu(raw)

output = neuron(
    inputs=[1.0, 2.0],
    weights=[0.5, -1.0],
    bias=1.5
)
print(f"Neuron output: {output:.1f}")

def relu(x): return max(0, x)

def neuron(inputs, weights, bias):
    # weighted sum of the inputs, then add the bias
    raw = sum(w + x for w, x in zip(weights, inputs)) + bias
    return relu(raw)

